-- ============================================================\n-- CUSTOMER PORTAL — Migration 10: Checkout State Machine & Warehouse\n-- ============================================================\n\n-- Order state history / audit timeline\nCREATE TABLE IF NOT EXISTS public.order_state_history (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  order_id BIGINT REFERENCES public.orders(id) ON DELETE CASCADE NOT NULL,\n  from_state TEXT,\n  to_state TEXT NOT NULL,\n  reason TEXT,\n  changed_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Customer warehouse storage reservations & requests\nCREATE TABLE IF NOT EXISTS public.customer_warehouse_storage (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  customer_id BIGINT REFERENCES public.customer_profiles(id) ON DELETE CASCADE NOT NULL,\n  space_m3 NUMERIC(10,3) NOT NULL DEFAULT 0,\n  start_date TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),\n  end_date TIMESTAMP WITH TIME ZONE,\n  status TEXT DEFAULT 'Pending' CHECK (status IN ('Pending','Approved','Expired','Cancelled')),\n  cost_per_period NUMERIC(15,2) DEFAULT 0,\n  period TEXT DEFAULT 'Monthly',\n  notes TEXT,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Search history & saved filters\nCREATE TABLE IF NOT EXISTS public.customer_search_history (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  portal_user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,\n  query_text TEXT NOT NULL,\n  filters_applied JSONB DEFAULT '{}'::jsonb,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Enable RLS\nALTER TABLE public.order_state_history ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.customer_warehouse_storage ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.customer_search_history ENABLE ROW LEVEL SECURITY;\n\n-- Policies\nCREATE POLICY IF NOT EXISTS \"Customers view their own order state history\"\n  ON public.order_state_history FOR SELECT\n  USING (EXISTS (\n    SELECT 1 FROM public.orders o\n    JOIN public.customer_profiles p ON p.id = o.customer_id -- Wait, orders might link to customer_profiles! Let's check how orders links to customers.\n    -- Since auth.uid() can view the order, we check user permissions directly on orders\n    WHERE o.id = order_state_history.order_id AND (o.user_id = auth.uid() OR EXISTS (\n      SELECT 1 FROM public.customer_profiles p WHERE p.portal_user_id = auth.uid() AND o.customer_id = p.id\n    ))\n  ));\n\nCREATE POLICY IF NOT EXISTS \"Customers view their own warehouse storage\"\n  ON public.customer_warehouse_storage FOR SELECT\n  USING (EXISTS (\n    SELECT 1 FROM public.customer_profiles p\n    WHERE p.id = customer_warehouse_storage.customer_id AND p.portal_user_id = auth.uid()\n  ));\n\nCREATE POLICY IF NOT EXISTS \"Customers manage their own warehouse storage requests\"\n  ON public.customer_warehouse_storage FOR INSERT\n  WITH CHECK (EXISTS (\n    SELECT 1 FROM public.customer_profiles p\n    WHERE p.id = customer_id AND p.portal_user_id = auth.uid()\n  ));\n\nCREATE POLICY IF NOT EXISTS \"Customers manage their own search history\"\n  ON public.customer_search_history FOR ALL\n  USING (portal_user_id = auth.uid());\n
